REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('279', '116', 'Situacion geografica', 'situacion-geografica-1856', '\n\n<p align=\"center\">\n  <img src=\"Images/mapas1.gif\"   alt=\"mapas1.gif (18429 bytes)\" align=\"left\"></p>\n    <p align=\"right\">&nbsp;</p>\n    <p align=\"center\"><u><strong><big><big><big><big><big>\n    <font  >MORATALLA</font><font  ><a target=\"_blank\" href=\"Images/situacion.jpg\"><font ><img border=\"0\" src=\"Images/situacion.jpg\"   align=\"right\"></font></a></font></big></big></big></big></big></strong></u></p>\n\n<p><strong><font  >&nbsp; </font>\n<font  >&nbsp;El t??rmino municipal de \nMoratalla tiene una extensi??n de 961 Km2, siendo uno de los m??s grandes de \nEspa??a, situada en el sureste espa??ol y Noroeste de la regi??n de Murcia, en una \nde las vertientes del cerro de San Jorge, 38?? 11&#39; 30&#39;&#39; latitud Norte, 1ª 47&#39; \n40&#39;&#39; longitud Oeste y con una altitud media sobre el nivel del mar de 681 \nmetros.</font></strong></p>\n\n<p><span ><font  >&nbsp;&nbsp;&nbsp; La \norograf??a pertenece a la reg??on Subb??tica, siendo la zona m??s monta??osa de la reg??on \nde Murcia, con m??s de 20 picos que sobrepasan los 1400 metros,&nbsp; entre ellos el techo \nde Murcia, con 2027 metros en el Pico de los Revolcadores.</font></span></p>\n\n<p><span ><font  >&nbsp;&nbsp;&nbsp; El \nclima es de los llamados de transici??n, donde encontramos zonas con clima t??picamente \nmediterraneo y clima continental en las zonas m??s altas.</font></span></p>\n\n<p><span ><font  >&nbsp;&nbsp;&nbsp; Por \nMoratalla pasan dos r??os, Alharabe y Benamor, son muy largos y sus caudales oscilan \nbastante de una estaci??n a otra, actualmente el R??o Benamor no tiene ning??n caudal al \npasar por Moratalla, debido a la gran sequ??a que sufre la zona. Ambos r??os se unen en el \nlugar llamado Molino de la Traviesa, desembocando finalmente en el R??o Segura.</font></span></p>\n\n<p>&nbsp;</p>\n\n<p><font  ><span >Extracto del \nlibro: Ciclo de Formaci??n Hist??rica para escolares &quot;Villa de Moratalla&quot;. \nPatrocinado por la CAM.</span></font></p>\n\n<p><big><big><font  ><u><strong>Distancias \nKilom??tricas.</strong></u></font></big></big></p>\n\n<p><font  ><big><u><strong>A PEDAN??AS.</strong></u></big></font></p>\n\n<table border=\"1\"   border cellpadding=\"0\" cellspacing=\"0\">\n  <tr>\n    <td  align=\"center\"><font  >\n    <span >PEDANIA</span></font></td>\n    <td  align=\"center\"><font  >\n    <span >KIL??METROS \n    (APROX.)</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CAMPO \n    B??JAR</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >14</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >BENIZAR</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >32</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CALAR \n    DE LA SANTA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >32</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CAMPO \n    DE SAN JUAN</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >21</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CA??ADA \n    DE LA CRUZ</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >57</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >EL \n    SABINAR</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >28</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >LA \n    ROGATIVA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >45</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >MAZUZA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >40</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >OTOS</span></font></td>\n    <td  align=\"right\"><span >\n    <font  >37</font></span></td>\n  </tr>\n</table>\n\n<p>&nbsp;</p>\n\n<p><font  ><big><u><strong>PUEBLOS Y \nCIUDADES CERCANAS.</strong></u></big></font></p>\n\n<table border=\"1\"  border  cellpadding=\"0\" cellspacing=\"0\">\n  <tr>\n    <td  align=\"center\"><font  >\n    <span >LOCALIDAD</span></font></td>\n    <td  align=\"center\"><font  >\n    <span >KIL??METROS \n    (APROX.)</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >BULLAS</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >33</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CALASPARRA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >19</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CARAVACA \n    DE LA CRUZ</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >13</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CEHEGIN</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >20</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >CIEZA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >57</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >HELL??N</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >75</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >LORCA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >71</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >MULA</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >47</span></font></td>\n  </tr>\n  <tr>\n    <td ><font  >\n    <span >SOCOVOS \n    (ALBACETE)</span></font></td>\n    <td  align=\"right\"><font  >\n    <span >36</span></font></td>\n  </tr>\n</table>\n\n<p align=\"center\">&nbsp;</p>\n\n<p align=\"center\">&nbsp;</p>\n', 'situacio.htm', '0', '2026-05-07 23:42:51');
