REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('285', '123', 'Insert Image', 'insert-image-9831', '\n\n<DIV id=divFileName >Image URL:</DIV>\n<INPUT ID=txtFileName type=text  tabIndex=10 onfocus=\"select()\">\n\n<DIV id=divAltText >Alternate Text:</DIV>\n<INPUT type=text ID=txtAltText tabIndex=15  onfocus=\"select()\">\n\n<FIELDSET id=fldLayout >\n<LEGEND id=lgdLayout>Layout</LEGEND>\n</FIELDSET>\n\n<FIELDSET id=fldSpacing >\n<LEGEND id=lgdSpacing>Spacing</LEGEND>\n</FIELDSET>\n\n<DIV id=divAlign >Alignment:</DIV>\n<SELECT size=1 ID=selAlignment tabIndex=20 >\n<OPTION id=optNotSet value=\"\"> Not set </OPTION>\n<OPTION id=optLeft value=left> Left </OPTION>\n<OPTION id=optRight value=right> Right </OPTION>\n<OPTION id=optTexttop value=textTop> Texttop </OPTION>\n<OPTION id=optAbsMiddle value=absMiddle> Absmiddle </OPTION>\n<OPTION id=optBaseline value=baseline SELECTED> Baseline </OPTION>\n<OPTION id=optAbsBottom value=absBottom> Absbottom </OPTION>\n<OPTION id=optBottom value=bottom> Bottom </OPTION>\n<OPTION id=optMiddle value=middle> Middle </OPTION>\n<OPTION id=optTop value=top> Top </OPTION>\n</SELECT>\n\n<DIV id=divHoriz >Horizontal:</DIV>\n<INPUT ID=txtHorizontal  type=text size=3 maxlength=3 value=\"\" tabIndex=25 onfocus=\"select()\">\n\n<DIV id=divBorder >Border Thickness:</DIV>\n<INPUT ID=txtBorder  type=text size=3 maxlength=3 value=\"\" tabIndex=21 onfocus=\"select()\">\n\n<DIV id=divVert >Vertical:</DIV>\n<INPUT ID=txtVertical  type=text size=3 maxlength=3 value=\"\" tabIndex=30 onfocus=\"select()\">\n\n<BUTTON ID=btnOK  type=submit tabIndex=40>OK</BUTTON>\n<BUTTON ID=btnCancel  type=reset tabIndex=45 onClick=\"window.close();\">Cancel</BUTTON>\n\n', 'insert_image.html', '0', '2026-05-07 23:42:51');
REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('286', '123', 'Insert Table', 'insert-table-3650', '\n\n<table border=0 cellspacing=0 cellpadding=0 >\n <tr>\n  <td>Rows: &nbsp;</td>\n  <td><input type=\"text\" name=\"rows\" value=\"4\"   maxlength=4></td>\n </tr>\n <tr>\n  <td>Cols:</td>\n  <td><input type=\"text\" name=\"cols\" value=\"3\"   maxlength=4></td>\n  <td width=10>&nbsp;</td>\n  <td>Width: &nbsp;</td>\n  <td>\n   <input type=\"text\" name=\"width\" value=\"100\"  maxlength=4>\n   <select name=\"widthExt\">\n    <option value=\"\">Pixels</option>\n    <option value=\"%\" selected>Percent</option>\n   </select>\n  </td>\n </tr>\n</table>\n\n\n<FIELDSET >\n<LEGEND>Layout</LEGEND>\n\n<table border=0 cellspacing=6 cellpadding=0>\n <tr>\n  <td height=21>Alignment:</td>\n  <td>\n   <select name=\"alignment\" size=1>\n   <option value=\"\">Not set</option>\n   <option value=\"left\">Left</option>\n   <option value=\"right\">Right</option>\n   <option value=\"textTop\">Texttop</option>\n   <option value=\"absMiddle\">Absmiddle</option>\n   <option value=\"baseline\">Baseline</option>\n   <option value=\"absBottom\">Absbottom</option>\n   <option value=\"bottom\">Bottom</option>\n   <option value=\"middle\">Middle</option>\n   <option value=\"top\">Top</option>\n   </select>\n  </td>\n </tr>\n <tr>\n  <td><nobr>Border Thickness:</nobr></td>\n  <td><input type=\"text\" name=\"border\" value=\"1\" size=4 ></td>\n </tr>\n</table>\n</FIELDSET>\n\n\n<FIELDSET >\n<LEGEND>Spacing</LEGEND>\n\n<table border=0 cellspacing=6 cellpadding=0>\n <tr>\n  <td><nobr>Cell Spacing:</nobr></td>\n  <td><input type=\"text\" name=\"cellspacing\" value=\"1\"  maxlength=4></td>\n </tr>\n <tr>\n  <td><nobr>Cell Padding:</nobr></td>\n  <td><input type=\"text\" name=\"cellpadding\" value=\"2\"  maxlength=4></td>\n </tr>\n</table>\n</FIELDSET>\n\n\n<div >\n <BUTTON  type=submit onclick=\"btnOKClick()\">OK</BUTTON><br>\n <BUTTON  type=reset onClick=\"window.close();\">Cancel</BUTTON>\n</div>\n\n', 'insert_table.html', '0', '2026-05-07 23:42:51');
