REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('293', '129', 'banda', 'banda-4858', '\n\n\n\n<p align=\"left\" >\n<embed   src=\"imagenes/anima_escudo_banda.swf\" align=\"left\"><big><font  ><big><big><font size=\"5\"><strong>&nbsp; </strong></font></big></big></font></big></p> \n\n\n<p align=\"left\" >\n<big><big><big>\n<font size=\"5\"><strong >\n<font  >BANDA  \nDE M??SICA DE MORATALLA</font></strong></font></big></big></big></p> \n\n\n<p align=\"left\" ><strong >\n<font  size=\"5\" >\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Programaci??n y \nensayos</font></strong></p> \n\n\n<p align=\"left\" >&nbsp;</p> \n\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td   valign=\"top\" rowspan=\"2\">\n    </td>\n    <td   rowspan=\"2\" valign=\"top\">\n    <p class=\"MsoNormal\" >\n    <font size=\"2\"  >&nbsp;</font><b><font  >REPERTORIO \n    INICIO&nbsp; TEMPORADA 2004:</font></b></p>\n    <p class=\"MsoNormal\" >\n    <u><b>\n    <font  size=\"2\" >BANDAS SONORAS</font></b></u></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Gladiator</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La misi??n</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Bailando con lobos</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La conquista del para??so</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Memorias de ??frica</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La lista de Sghindler</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Braveheart</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- El padrino</font></p>\n    <p class=\"MsoNormal\" >\n    <u><b><font  size=\"2\" >PASACALLES Y MARCHAS</font></b></u></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Luis</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Bajo la doble aguila</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Anta??ona</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Homenaje a Pep??n Liria</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Benaguacil</font></p>\n    <p class=\"MsoNormal\" >\n    <u><b><font  size=\"2\" >OBRAS ESPA??OLAS (o \n    basadas en m??sica espa??ola)</font></b></u></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Goyescas</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Tambor de granaderos</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- El camino real</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La Leyenda del beso</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La Gran V??a</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Alma de Dios</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- El Bateo</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Una noche en Granada</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Sevilla</font></p>\n    <p class=\"MsoNormal\" >\n    <u><b><font  size=\"2\" >PASODOBLES</font></b></u></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- La Ca??ada</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- María Esparza</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- En er mundo</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Mujer esteponera</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >- Tercio de quites</font></p>\n    </td>\n    <td   valign=\"top\">\n    <p >\n    &nbsp;</p>\n    <p  align=\"justify\">\n    <font  size=\"2\" >&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Cumplidos \n    cuatro a??o que comenzamos esta nueva etapa de la Banda de M??sica de \n    Moratalla conmigo como director y recogiendo vuestras inquietudes, he \n    pensado en una programaci??n montada sobre dos grandes ejes: un concierto de \n    bandas sonoras y un concierto de m??sica espa??ola. Estas programaciones \n    supondr??n en su mayor??a una recopilaci??n del trabajo realizado durante este \n    tiempo, de forma que podremos ver las diferencias interpretativas y \n    resultados de las ??pocas en que tocamos estas obras compar??ndolas con la \n    nueva situaci??n de la Banda.</font><p  align=\"justify\">\n    <font  size=\"2\" >&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; \n    Supondr?? un trabajo recopilatorio que pretende revivir momentos pasados. \n    Adem??s, permitir?? que los nuevos componentes se puedan sumar al conocimiento \n    de este repertorio y las dificultades que conlleva y cerrar una etapa antes \n    de abrir otra con nuevos y numerosos retos. Gracias por la confianza y \n    colaboraci??n de depositais en m??.</font><p  align=\"justify\">\n    &nbsp;<p  align=\"center\">\n    <font  size=\"2\" >Espero que sea de vuestro \n    agrado</font><p  align=\"center\">\n    <font  size=\"2\" >Vuestro Director.</font></td>\n    <td   valign=\"top\"></td>\n  </tr>\n  <tr>\n    <td   valign=\"top\">\n    <div >\n      <p align=\"left\" >\n      <font  size=\"2\" >- Los ensayos deben traerse \n      preparados.</font></p>\n      <p align=\"left\" >\n      &nbsp;</p>\n      <p align=\"left\" >\n      <font  size=\"2\" >- El ensayo del \n      viernes comenzar?? a las 21:30, para preparar el material y calentar, a \n      las 21:45, para afinaci??n y ensayo.</font></p>\n      <p align=\"left\" >\n      &nbsp;</p>\n      <p align=\"left\" >\n      <font  size=\"2\" >- El ensayo del domingo comenzar?? a las \n      11:30, para preparar el material y calentar, a \n      las 11:45, para afinaci??n y ensayo.</font></p>\n      <p align=\"left\" >\n      &nbsp;</p>\n      <p align=\"left\" >\n      <font  size=\"2\" >- En ensayo ser?? contin??o.</font></p>\n      <p align=\"left\" >\n      &nbsp;</p>\n      <p align=\"left\" >\n      <font  size=\"2\" >- Traer material para poder \n      tomas las anotaciones que se precisen, sobre las partituras</font></p>\n      <p align=\"right\" ><b>\n      <font  size=\"1\" >Doroteo Lude??a L??pez</font></b></p>\n      <p align=\"right\" ><b>\n      <font  size=\"1\" >Director</font></b></div>\n    </td>\n    <td   valign=\"top\">&nbsp;</td>\n  </tr>\n  <tr>\n    <td  >\n&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td   colspan=\"2\">&nbsp;</td>\n  </tr>\n  </table>\n\n<p align=\"center\">&nbsp;</p>\n\n<p align=\"left\"><font ><big>&nbsp;&nbsp;&nbsp;</big></font></p>\n\n<span >\n\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, Espa??a,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, ca??ada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, monta??a, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez,futbol, automovilismo, tamborada,ciclismo, rocasas\n</font></span><font ></span></font></p>\n\n\n', 'banda_ensayos.htm', '0', '2026-05-07 23:42:51');
